import{c as t,Q as o,j as r,m as l}from"./chunks/framework.BXc4yaFE.js";const u=JSON.parse('{"title":"/loop 與 /schedule — Claude Code 最強自動化雙工具 — @bcherny","description":"","frontmatter":{"title":"/loop 與 /schedule — Claude Code 最強自動化雙工具 — @bcherny","author":"Boris Cherny（@bcherny）","date":"2026-03-30T00:00:00.000Z","source":"https://x.com/bcherny/status/2038454341884154269","type":"tweet"},"headers":[],"relativePath":"research/tweets/2026-03-30-@bcherny-154269.md","filePath":"research/tweets/2026-03-30-@bcherny-154269.md","lastUpdated":1779894392000}'),a={name:"research/tweets/2026-03-30-@bcherny-154269.md"};function s(d,e,c,i,n,h){return o(),r("div",null,[...e[0]||(e[0]=[l('<h1 id="loop-與-schedule-—-claude-code-最強自動化雙工具-—-bcherny" tabindex="-1">/loop 與 /schedule — Claude Code 最強自動化雙工具 — @bcherny <a class="header-anchor" href="#loop-與-schedule-—-claude-code-最強自動化雙工具-—-bcherny" aria-label="Permalink to &quot;/loop 與 /schedule — Claude Code 最強自動化雙工具 — @bcherny&quot;">​</a></h1><p><strong>來源</strong>：<a href="https://x.com/bcherny/status/2038454341884154269" target="_blank" rel="noreferrer">https://x.com/bcherny/status/2038454341884154269</a><strong>作者</strong>：Boris Cherny（@bcherny） <strong>發布日期</strong>：2026-03-30 <strong>收錄日期</strong>：2026-05-01 <strong>類型</strong>：推文 <strong>統計</strong>：1603 likes · 52 retweets · 1531 bookmarks · 320593 views</p><hr><h2 id="全文" tabindex="-1">全文 <a class="header-anchor" href="#全文" aria-label="Permalink to &quot;全文&quot;">​</a></h2><p>3/ Two of the most powerful features in Claude Code: /loop and /schedule</p><p>Use these to schedule Claude to run automatically at a set interval, for up to a week at a time.</p><p>I have a bunch of loops running locally:</p><ul><li>/loop 5m /babysit, to auto-address code review, auto-rebase, and shepherd my PRs to production</li><li>/loop 30m /slack-feedback, to automatically put up PRs for Slack feedback every 30 mins</li><li>/loop /post-merge-sweeper to put up PRs to address code review comments I missed</li><li>/loop 1h /pr-pruner to close out stale and no longer necessary PRs</li><li>lots more!..</li></ul><p>Experiment with turning workflows into skills + loops. It&#39;s powerful.</p><p><a href="https://code.claude.com/docs/en/scheduled-tasks" target="_blank" rel="noreferrer">https://code.claude.com/docs/en/scheduled-tasks</a></p><hr><h2 id="研究摘要" tabindex="-1">研究摘要 <a class="header-anchor" href="#研究摘要" aria-label="Permalink to &quot;研究摘要&quot;">​</a></h2><p><strong>TL;DR</strong>：Claude Code 作者親身展示 /loop + /schedule 組合，將 PR 守護、Slack 回饋收集等重複性 PR 工作流轉為定時自動執行迴圈。</p><h3 id="核心論點" tabindex="-1">核心論點 <a class="header-anchor" href="#核心論點" aria-label="Permalink to &quot;核心論點&quot;">​</a></h3><ol><li><code>/loop</code> 與 <code>/schedule</code> 是 Claude Code 的「最強兩個功能」——作者語氣強烈，非一般評論</li><li><code>/loop</code> 可設定間隔（5m / 30m / 1h）無限循環執行任一 Skill，最長持續一週</li><li>實際運行的 4 個迴圈展示了從 PR 監護（/babysit）、Slack 回饋 PR 化（/slack-feedback）、post-merge 掃尾（/post-merge-sweeper）到廢 PR 清理（/pr-pruner）的完整生命週期自動化</li><li>核心哲學：<strong>把工作流封裝成 Skill，再用 Loop 驅動它</strong>——Skill 是原子操作，Loop 是排程引擎</li><li>這是 thread 第 3 則（3/），說明 Boris 在這個 thread 系統性分享 Claude Code 隱藏/進階功能</li></ol><h3 id="關鍵數據-工具" tabindex="-1">關鍵數據 / 工具 <a class="header-anchor" href="#關鍵數據-工具" aria-label="Permalink to &quot;關鍵數據 / 工具&quot;">​</a></h3><ul><li><code>/loop 5m /babysit</code>：每 5 分鐘執行，PR 自動 rebase 與 code review 回應</li><li><code>/loop 30m /slack-feedback</code>：每 30 分鐘自動化 Slack 回饋 → PR 轉換</li><li><code>/loop /post-merge-sweeper</code>：merge 後遺漏 review comment 補處理</li><li><code>/loop 1h /pr-pruner</code>：每小時清理 stale PR</li><li>官方文件：<a href="https://code.claude.com/docs/en/scheduled-tasks" target="_blank" rel="noreferrer">https://code.claude.com/docs/en/scheduled-tasks</a></li><li>最長執行上限：一週</li></ul><h3 id="批判性觀察" tabindex="-1">批判性觀察 <a class="header-anchor" href="#批判性觀察" aria-label="Permalink to &quot;批判性觀察&quot;">​</a></h3><ol><li>這 4 個迴圈全部依賴 /babysit、/slack-feedback 等<strong>自定義 Skill</strong>，但推文未展示這些 Skill 的內容——可行動性需要使用者自行設計對應 Skill，門檻不低</li><li><code>/loop</code> 在 cc-workspace 的 <code>routines.md</code> 已記載，但缺少 Boris 親身驗證的具體 loop 配方——此推文補充了真實使用案例，是對 routines.md 的高品質補充</li><li>在無本機 terminal 常駐的情境下 /loop 會中斷（vs /schedule 雲端執行不需 terminal），推文未說明兩者差異，可能誤導使用者選錯工具</li></ol><hr><h2 id="評分" tabindex="-1">評分 <a class="header-anchor" href="#評分" aria-label="Permalink to &quot;評分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>說明</th></tr></thead><tbody><tr><td>A. Workspace 可行動性 (30%)</td><td>8/10</td><td>/loop 語法、4 個具名 loop 配方直接可複製到 cc-workspace routines；需補充對應 Skill 定義</td></tr><tr><td>B. 創新性 (20%)</td><td>6/10</td><td>/loop 功能本身已在 routines.md 記錄，但 Boris 親身示範的 babysit/pr-pruner 等配方是新增資訊</td></tr><tr><td>C. 證據品質 (20%)</td><td>7/10</td><td>第一手使用者（Claude Code 作者本人）親自展示，4 個真實 loop 配方，配有官方文件連結</td></tr><tr><td>D. 技術深度 (15%)</td><td>6/10</td><td>語法層已清楚（/loop interval /skill），但未展示 Skill 實作細節或失敗處理機制</td></tr><tr><td>E. 泛化性 (15%)</td><td>7/10</td><td>PR 工作流自動化對任何有 PR 流程的 repo 通用；/babysit 等 Skill 需依專案客製化</td></tr><tr><td><strong>加權總分</strong></td><td><strong>6.90/10</strong></td><td>A×0.3+B×0.2+C×0.2+D×0.15+E×0.15</td></tr></tbody></table><p><strong>整合決策</strong>：Rule <strong>理由</strong>：核心洞見是「Skill + Loop = 工作流自動化」的組合哲學，補充 routines.md 中 /loop 的實戰配方與使用情境說明。</p>',23)])])}const b=t(a,[["render",s]]);export{u as __pageData,b as default};
